+function kebabToCamelCase(value: string): string {
+  return value.replace(/-([a-z0-9])/gi, (_, character) => character.toUpperCase());
+}
+
+function flattenConfig(
+  value: Record<string, unknown>,
+  prefix = "",
+): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const [rawKey, item] of Object.entries(value)) {
+    const key = prefix ? `${prefix}.${kebabToCamelCase(rawKey)}` : kebabToCamelCase(rawKey);
+    if (isPlainObject(item)) {
+      Object.assign(result, flattenConfig(item, key));
+    } else {
+      result[key] = item;
+    }
+  }
+  return result;
+}
+
+function isPlainObject(value: unknown): value is Record<string, unknown> {
+  return typeof value === "object" && value !== null && !Array.isArray(value) &&
+    Object.getPrototypeOf(value) === Object.prototype;
+}
+
+function parseConfig(
+  content: string,
+  path: string,
+  format: string,
+  parser?: (content: string) => Record<string, unknown>,
+): Record<string, unknown> {
