+
+function parseRc(content: string): Record<string, unknown> {
+  const result: Record<string, unknown> = {};
+  for (const sourceLine of content.split(/\\r?\
/)) {
+    const line = sourceLine.trim();
+    if (!line || line.startsWith("#")) continue;
+    const separator = line.indexOf("=");
+    if (separator < 1) throw new TypeError(`Invalid RC entry: ${sourceLine}`);
+    const key = line.slice(0, separator).trim();
+    let value = line.slice(separator + 1).trim();
+    if (value.startsWith('"')) {
+      if (!value.endsWith('"') || value.length < 2) throw new TypeError(`Unterminated quoted value: ${sourceLine}`);
+      value = value.slice(1, -1);
+    } else if (value === "true" || value === "false") {
+      result[key] = value === "true";
+      continue;
+    } else if (/^-?(?:\\d+\\.?\\d*|\\.\\d+)$/.test(value)) {
+      result[key] = Number(value);
+      continue;
+    }
+    result[key] = value;
+  }
+  return result;
